"use client";
import * as React from "react";
import { textareaAnatomy } from "@tessera/core";

export interface TextareaProps extends React.TextareaHTMLAttributes<HTMLTextAreaElement> {
  label: string;
  description?: string;
  error?: string;
}

export const Textarea = React.forwardRef<HTMLTextAreaElement, TextareaProps>(function Textarea(
  { label, description, error, id: idProp, className, style, ...rest },
  ref
) {
  const autoId = React.useId();
  const id = idProp ?? `${autoId}-textarea`;
  const descriptionId = `${autoId}-description`;
  const errorId = `${autoId}-error`;
  const invalid = error !== undefined;

  const describedBy =
    [description && descriptionId, invalid && errorId].filter(Boolean).join(" ") || undefined;

  return (
    <div {...textareaAnatomy.attrs("root")} className={className} style={style}>
      <label {...textareaAnatomy.attrs("label")} htmlFor={id}>
        {label}
      </label>
      <textarea
        {...textareaAnatomy.attrs("input")}
        id={id}
        ref={ref}
        data-invalid={invalid || undefined}
        aria-invalid={invalid || undefined}
        aria-describedby={describedBy}
        {...rest}
      />
      {description && (
        <p {...textareaAnatomy.attrs("description")} id={descriptionId}>
          {description}
        </p>
      )}
      {invalid && (
        <p {...textareaAnatomy.attrs("error")} id={errorId} role="alert">
          {error}
        </p>
      )}
    </div>
  );
});

@layer tessera.recipes {
  [data-scope="textarea"][data-part="root"] {
    display: flex;
    flex-direction: column;
    gap: var(--ts-space-1);
    max-width: 100%;
  }

  [data-scope="textarea"][data-part="label"] {
    font-size: var(--ts-font-size-sm);
    font-weight: var(--ts-font-weight-medium);
    color: var(--ts-fg-default);
  }

  [data-scope="textarea"][data-part="input"] {
    appearance: none;
    width: 100%;
    min-height: 5rem;
    padding: var(--ts-space-2) var(--ts-space-3);
    border: 1px solid var(--ts-border-default);
    border-radius: var(--ts-radius-md);
    background: var(--ts-bg-surface);
    color: var(--ts-fg-default);
    font-size: var(--ts-font-size-sm);
    font-family: var(--ts-font-family-sans);
    line-height: var(--ts-font-leading-normal);
    resize: vertical;
    transition: border-color var(--ts-duration-fast) var(--ts-easing-standard);
  }

  [data-scope="textarea"][data-part="input"]::placeholder {
    color: var(--ts-fg-subtle);
  }

  [data-scope="textarea"][data-part="input"]:hover:not(:disabled) {
    border-color: var(--ts-border-strong);
  }

  [data-scope="textarea"][data-part="input"]:focus-visible {
    outline: 2px solid var(--ts-ring-color);
    outline-offset: -1px;
    border-color: transparent;
  }

  [data-scope="textarea"][data-part="input"][data-invalid] {
    border-color: var(--ts-danger-default);
  }

  [data-scope="textarea"][data-part="description"] {
    font-size: var(--ts-font-size-xs);
    color: var(--ts-fg-muted);
  }

  [data-scope="textarea"][data-part="error"] {
    font-size: var(--ts-font-size-xs);
    color: var(--ts-danger-fg);
  }
}
